import{_ as a,o as s,c as t,an as n}from"./chunks/framework.ubcH7j8_.js";const u=JSON.parse('{"title":"Feature: nervous-system","description":"","frontmatter":{},"headers":[],"relativePath":"ard/NERVOUS-SYSTEM.md","filePath":"ard/NERVOUS-SYSTEM.md","lastUpdated":1772822285000}'),r={name:"ard/NERVOUS-SYSTEM.md"};function i(o,e,l,c,d,p){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="feature-nervous-system" tabindex="-1">Feature: nervous-system <a class="header-anchor" href="#feature-nervous-system" aria-label="Permalink to &quot;Feature: nervous-system&quot;">​</a></h1><blockquote><p>Spec folder will be: <code>specs/NNN-nervous-system/</code> HLD: <code>docs/ard/NERVOUS-SYSTEM-HLD.md</code></p></blockquote><h2 id="concept" tabindex="-1">Concept <a class="header-anchor" href="#concept" aria-label="Permalink to &quot;Concept&quot;">​</a></h2><p>NATS and Pulsar together form the platform&#39;s &quot;nervous system&quot; — the connective tissue through which agents communicate, data pre-positions, and inference results flow reactively. The primary outcome is reducing TTFT (Time to First Token) from ~3-5s to sub-200ms at P50.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NATS    = fast nerves    — real-time impulse delivery, ephemeral, request-reply</span></span>
<span class="line"><span>Pulsar  = spinal cord    — durable pathways, fan-out, replay, backpressure</span></span>
<span class="line"><span>Redis   = muscle memory  — cached context, hot state</span></span></code></pre></div><h2 id="role-in-the-broader-arc-infrastructure" tabindex="-1">Role in the Broader ARC Infrastructure <a class="header-anchor" href="#role-in-the-broader-arc-infrastructure" aria-label="Permalink to &quot;Role in the Broader ARC Infrastructure&quot;">​</a></h2><p>The nervous system is the <strong>foundation layer</strong> of ARC as AI infrastructure. Every higher-level capability depends on it:</p><ul><li>Speed goal (sub-200ms TTFT) is only achievable with NATS token streaming (Phase 1)</li><li>The Resource + Event pattern (REST mutation → Pulsar topic) requires Phase 3 Pulsar fan-out</li><li>The accuracy loop (arc-guard (RoboCop / Guardrails), arc-critic (Gordon Ramsay / Critic), arc-gym (Ivan Drago / Trainer)) subscribes to Pulsar topics produced in Phase 3</li><li>Voice (arc-voice-agent (Scarlett / Voice)) consumes inference streams from Pulsar</li></ul><p>Phase 3 completion unlocks the full ARC infrastructure vision. Phases 1 and 2 are Sherlock-internal; Phase 3 is the platform-wide event backbone.</p><h2 id="current-bottleneck-chain" tabindex="-1">Current Bottleneck Chain <a class="header-anchor" href="#current-bottleneck-chain" aria-label="Permalink to &quot;Current Bottleneck Chain&quot;">​</a></h2><p>Every request today flows sequentially:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Request arrives (NATS)</span></span>
<span class="line"><span>  → embed query (CPU SentenceTransformer, ~100ms, BLOCKS)</span></span>
<span class="line"><span>  → DB vector search (Postgres HNSW, ~50ms, BLOCKS)</span></span>
<span class="line"><span>  → build prompt + inject context</span></span>
<span class="line"><span>  → LLM.ainvoke()  ← waits for ALL prior steps</span></span>
<span class="line"><span>  → full response buffered in memory</span></span>
<span class="line"><span>  → NATS reply sent (single blob)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>TTFT = sum of ALL steps. First token only when last byte is ready.</span></span></code></pre></div><p>The NATS handlers (<code>nats_handler.py</code>, <code>openai_nats_handler.py</code>) use <code>invoke_graph()</code> which buffers the full response. The streaming path (<code>stream_graph()</code>) already exists in <code>graph.py</code> but is only wired to HTTP/SSE — not NATS or Pulsar.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     ┌───────────────────────────────────────┐</span></span>
<span class="line"><span>Client               │           NERVOUS SYSTEM               │</span></span>
<span class="line"><span>  │                  │                                         │</span></span>
<span class="line"><span>  │──NATS request──▶ │  reasoner.request                       │</span></span>
<span class="line"><span>  │                  │    ├── spawn: embed query (threadpool)  │</span></span>
<span class="line"><span>  │                  │    ├── spawn: fetch context (Redis)     │</span></span>
<span class="line"><span>  │◀─ token chunk 1 ─│    └── begin LLM stream immediately     │</span></span>
<span class="line"><span>  │◀─ token chunk 2 ─│         inject retrieval when ready ──▶│──▶ Pulsar: reasoner-inference-{id}</span></span>
<span class="line"><span>  │◀─ token chunk 3 ─│                                         │</span></span>
<span class="line"><span>  │                  │  Pulsar subscriptions (fan-out):        │</span></span>
<span class="line"><span>  │                  │    reasoner-requests  → durable async   │</span></span>
<span class="line"><span>  │                  │    reasoner-results   → downstream subs │</span></span>
<span class="line"><span>  └──────────────────└─────────────────────────────────────── ┘</span></span></code></pre></div><h2 id="phased-implementation" tabindex="-1">Phased Implementation <a class="header-anchor" href="#phased-implementation" aria-label="Permalink to &quot;Phased Implementation&quot;">​</a></h2><h3 id="phase-1-—-quick-wins-highest-ttft-impact-no-infra-changes" tabindex="-1">Phase 1 — Quick Wins (highest TTFT impact, no infra changes) <a class="header-anchor" href="#phase-1-—-quick-wins-highest-ttft-impact-no-infra-changes" aria-label="Permalink to &quot;Phase 1 — Quick Wins (highest TTFT impact, no infra changes)&quot;">​</a></h3><p><strong>1. Token streaming over NATS</strong></p><ul><li>Biggest single TTFT improvement: 3-5s → ~200ms</li><li><code>nats_handler.py</code> and <code>openai_nats_handler.py</code> call <code>invoke_graph()</code> (buffers full response)</li><li>Replace with <code>stream_graph()</code> and publish token chunks to <code>reasoner.stream.{request_id}</code></li><li><code>stream_graph()</code> in <code>graph.py</code> already works — just unwired from NATS</li><li>Client subscribes to <code>reasoner.stream.{request_id}</code> for chunks, <code>reasoner.v1.result</code> for completion signal</li></ul><p><strong>2. CPU embedding off critical path</strong></p><ul><li><code>memory.py:92</code> — <code>SentenceTransformer.encode()</code> runs synchronously, blocking for ~100ms</li><li>Wrap in <code>asyncio.run_in_executor()</code> with a dedicated <code>ThreadPoolExecutor(max_workers=2)</code></li><li>No graph changes needed</li></ul><p><strong>3. TTFT baseline metrics</strong></p><ul><li><code>observability.py</code> — add <code>ttft_seconds</code> histogram</li><li>Measure time from request receive → first token emitted (not full response complete)</li><li>Establishes baseline before further optimizations</li></ul><h3 id="phase-2-—-parallel-pipeline" tabindex="-1">Phase 2 — Parallel Pipeline <a class="header-anchor" href="#phase-2-—-parallel-pipeline" aria-label="Permalink to &quot;Phase 2 — Parallel Pipeline&quot;">​</a></h3><p><strong>4. Parallel retrieve + LLM start</strong></p><ul><li><code>graph.py:185</code> <code>invoke_graph</code> runs <code>retrieve_context</code> → <code>generate_response</code> sequentially</li><li>Restructure: start LLM with empty/partial context, inject retrieval results as they arrive via LangGraph state</li><li>Removes ~150ms retrieval latency from critical path</li></ul><p><strong>5. Redis context cache (Sonic)</strong></p><ul><li>Sonic is already in the platform — wire it in as a cache layer</li><li>Cache key: <code>(user_id, query_embedding_hash)</code> → <code>context_chunks</code>, TTL ~5min</li><li><code>memory.py</code> checks cache first, falls back to Postgres HNSW on miss</li><li>First request populates cache; repeated questions from same user get sub-10ms retrieval</li></ul><h3 id="phase-3-—-pulsar-durable-fan-out" tabindex="-1">Phase 3 — Pulsar Durable Fan-out <a class="header-anchor" href="#phase-3-—-pulsar-durable-fan-out" aria-label="Permalink to &quot;Phase 3 — Pulsar Durable Fan-out&quot;">​</a></h3><p><strong>6. Enable Pulsar as event backbone</strong></p><ul><li>Pulsar already deployed in <code>reason</code> profile, disabled by default (<code>SHERLOCK_PULSAR_ENABLED=false</code>)</li><li>Each inference publishes token-level events to <code>reasoner-inference-{id}</code> topic</li><li>Multiple downstream subscribers (voice pipeline, logging, analytics) consume independently without blocking LLM</li><li><code>pulsar_handler.py:79-134</code> <code>_process</code> method → replace with streaming publish variant</li></ul><p><strong>7. NATS → Pulsar graceful degradation</strong></p><ul><li>Under load: NATS request-reply with 500ms timeout</li><li>If timeout: queue to Pulsar <code>reasoner-requests</code> for durable async processing</li><li>Result delivered to original caller via correlation ID when ready</li><li>Prevents overload from cascading into dropped requests</li></ul><h2 id="ttft-improvement-estimates" tabindex="-1">TTFT Improvement Estimates <a class="header-anchor" href="#ttft-improvement-estimates" aria-label="Permalink to &quot;TTFT Improvement Estimates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Optimization</th><th>Latency Saved</th><th>Complexity</th></tr></thead><tbody><tr><td>1</td><td>Streaming over NATS</td><td>1.9-4.9s</td><td>Medium</td></tr><tr><td>1</td><td>Embedding off critical path</td><td>100ms</td><td>Low</td></tr><tr><td>2</td><td>Parallel retrieve + generate</td><td>150-300ms</td><td>Medium</td></tr><tr><td>2</td><td>Redis context cache</td><td>200-400ms (cache hits)</td><td>Medium</td></tr><tr><td>3</td><td>Pulsar token fan-out</td><td>Throughput scale-out</td><td>High</td></tr><tr><td>3</td><td>NATS/Pulsar fallback</td><td>P95 improvement</td><td>Low</td></tr></tbody></table><p><strong>Target:</strong> P50 TTFT &lt; 200ms (from current ~3-5s)</p><h2 id="key-files" tabindex="-1">Key Files <a class="header-anchor" href="#key-files" aria-label="Permalink to &quot;Key Files&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>services/reasoner/src/reasoner/graph.py             # invoke_graph, stream_graph, node definitions</span></span>
<span class="line"><span>services/reasoner/src/reasoner/streaming.py         # GraphStreamingAdapter — reuse for NATS</span></span>
<span class="line"><span>services/reasoner/src/reasoner/nats_handler.py      # replace invoke_graph → stream_graph</span></span>
<span class="line"><span>services/reasoner/src/reasoner/openai_nats_handler.py</span></span>
<span class="line"><span>services/reasoner/src/reasoner/pulsar_handler.py    # add token-level publish + Resource+Event topics</span></span>
<span class="line"><span>services/reasoner/src/reasoner/memory.py            # embedding threadpool + Redis cache layer</span></span>
<span class="line"><span>services/reasoner/src/reasoner/observability.py     # add ttft_seconds histogram</span></span>
<span class="line"><span>services/reasoner/src/reasoner/config.py            # NATS subjects, Pulsar topics, Redis URL</span></span>
<span class="line"><span>services/reasoner/contracts/asyncapi.yaml           # add stream subject + Pulsar topic definitions</span></span>
<span class="line"><span>services/messaging/service.yaml                     # arc-pulse (Flash / NATS) — already deployed</span></span>
<span class="line"><span>services/cache/service.yaml                         # arc-db-cache (Sonic / Redis) — already deployed</span></span>
<span class="line"><span>services/streaming/service.yaml                     # arc-stream (Dr. Strange / Pulsar) — reason profile</span></span></code></pre></div><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><code>decouple-service-codenames</code> must land first — in progress on current branch</li><li>arc-db-cache (Sonic / Redis) must be verified healthy in <code>think</code> profile before Phase 2 cache work</li><li>arc-stream (Dr. Strange / Pulsar) must be verified healthy in <code>reason</code> profile before Phase 3</li></ul><h2 id="decisions-resolved" tabindex="-1">Decisions (resolved) <a class="header-anchor" href="#decisions-resolved" aria-label="Permalink to &quot;Decisions (resolved)&quot;">​</a></h2><ol><li>NATS token streaming uses dedicated subject <code>reasoner.stream.{request_id}</code> — not reply-to inbox. Cleaner fan-out, client subscribes explicitly.</li><li>Redis cache invalidation: TTL-based (5min default) + explicit invalidation when conversation history changes (new message appended resets key).</li><li>Voice pipeline (arc-voice-agent (Scarlett / Voice)) consumes from Pulsar (durable, async) — not NATS. NATS is for real-time client streaming only.</li><li><code>stream_graph()</code> is the default path for all transports. Buffering (<code>invoke_graph</code>) is opt-in only.</li></ol><h2 id="implementation-status" tabindex="-1">Implementation Status <a class="header-anchor" href="#implementation-status" aria-label="Permalink to &quot;Implementation Status&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Status</th><th>Commit</th></tr></thead><tbody><tr><td>Phase 1 — Fast Nerves</td><td>✅ Complete</td><td><code>feat(reasoner): Phase 1 — NATS token streaming + embedding off critical path</code></td></tr><tr><td>Phase 2 — Muscle Memory</td><td>✅ Complete</td><td><code>feat(reasoner): Phase 2 — parallel retrieval + arc-db-cache (Sonic / Redis) context cache</code></td></tr><tr><td>Phase 3 — Spinal Cord</td><td>✅ Complete</td><td><code>feat(reasoner): Phase 3 — Pulsar event backbone, RoboCop guards, DLQ fallback</code></td></tr><tr><td>Integration verification</td><td>⏳ Pending</td><td>Requires live <code>reason</code> profile environment</td></tr></tbody></table>`,44)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
